1	import { describe, it, expect } from "vitest";
2	import { run } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge: empty
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const out = run({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(out).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items (single item, newcomer 0 yrs, first contract: +10% first insurance, +5G fee)
15	  it.todo("single plain sword (0 yrs, first quote) → 100 + 10 + 5 = 115 G");
16	  it.todo("single plain amulet (0 yrs, first quote) → 60 + 6 + 5 = 71 G");
17	  it.todo("single plain staff (0 yrs, first quote) → 80 + 8 + 5 = 93 G");
18	  it.todo("single plain potion (0 yrs, first quote) → 40 + 4 + 5 = 49 G");
19	
20	  // Components and 3-alike block
21	  it.todo("2 runes → base 50 G; with first insurance 55 + 5 fee = 60 G");
22	  it.todo("3 runes → block: base 60 G; 66 + 5 = 71 G");
23	  it.todo("4 runes → no block: 100 G base; 110 + 5 = 115 G");
24	  it.todo("7 runes → 175 G base; 192.5→193 + 5 = 198 G (rounded up in MHPCO favor)");
25	  it.todo("alike: 2 runes + 1 moonstone → 75 G base (no block, different types)");
26	  it.todo("alike: 3 runes + 3 moonstones → 120 G base (two separate blocks)");
27	
28	  // Item-specific modifiers
29	  it.todo("cursed sword adds 50% to sword base premium");
30	  it.todo("sword enchantment 5 adds 30% (high enchantment threshold)");
31	  it.todo("sword enchantment 4 → no high-enchantment surcharge");
32	  it.todo("cursed sword enchantment 5 → both surcharges apply");
33	
34	  // Policy-wide modifiers
35	  it.todo("loyalty: customer with exactly 2 years receives 20% discount");
36	  it.todo("first insurance: +10% on policy base premium");
37	  it.todo("follow-up contract: -15% on second and later contracts");
38	  it.todo("processing fee 5G added at the end");
39	
40	  // Modifier scope (multi-item)
41	  it.todo("cursed sword + plain amulet: 100+60 base, +50 cursed surcharge (cursed only), +5 fee = 215 with no other modifiers — actually 210 before fee per spec");
42	
43	  // Rounding
44	  it.todo("premium 197.5 G → 198 G (rounded up)");
45	  it.todo("payout 350.5 G → 350 G (rounded down)");
46	
47	  // Edge: unknown item type
48	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results to stdout");
49	
50	  // Integration examples
51	  it.todo("integration: newcomer 0 yrs, cursed sword (steel, ench 3) → premium 165 G");
52	  it.todo("integration: 3-yr customer, second quote, cursed sword ench 7 → premium 160 G");
53	
54	  // Claim: standard reimbursement
55	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (500 - 100 deductible)");
56	  it.todo("rune damage 200 → payout 100 (no special clause for components)");
57	
58	  // Claim: enchantment threshold
59	  it.todo("dragon sword, ench 8, damage 1000 → payout 400 (high-enchantment 50% applies first, then deductible)");
60	  it.todo("dragon sword, ench 9, damage 1000 → payout 400 (both clauses; 50% wins, then deductible)");
61	  it.todo("dragon sword, ench 5, damage 800 → payout 700 (only dragon clause: full reimbursement, then deductible)");
62	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (only high-enchantment clause)");
63	
64	  // Claim: deductible per item
65	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
66	
67	  // Multiple items of same type
68	  it.todo("two swords policy → insurance sum 2000, cap 4000; dragon attack damages both → two separate damages with own deductibles");
69	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");
70	
71	  // Cap
72	  it.todo("sword + amulet → insurance sum 1600, cap 3200");
73	  it.todo("cursed sword cap is based on unmodified insurance value: cap 2000");
74	  it.todo("sword + 3 runes (block) → insurance sum 1750 (block discount affects premium only)");
75	  it.todo("sword cap 2000: two claims of 1500 each → first payout 1400 cap remaining 600; second payout 600 cap remaining 0");
76	
77	  // Claim error cases
78	  it.todo("claim references damage for item not in policy → CLI exits non-zero");
79	  it.todo("claim with negative damage amount → CLI exits non-zero");
80	});
